import{_ as e,a,b as i,c as o,d as l,e as r,f as s,g as n,h as c,i as h,j as g}from"./chunks/apm_support_indicator.CS1HkOWN.js";import{_ as d,a as m,b as u,c as p,d as q,e as b}from"./chunks/battery_indicator.Dw2X-Wau.js";import{_,o as v,c as y,ag as f}from"./chunks/framework.B9unkguw.js";const C=JSON.parse('{"title":"飞行视图工具栏","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/fly_view/fly_view_toolbar.md","filePath":"zh/qgc-user-guide/fly_view/fly_view_toolbar.md"}'),S={name:"zh/qgc-user-guide/fly_view/fly_view_toolbar.md"};function x(P,t,w,R,T,k){return v(),y("div",null,t[0]||(t[0]=[f('<h1 id="飞行视图工具栏" tabindex="-1">飞行视图工具栏 <a class="header-anchor" href="#飞行视图工具栏" aria-label="Permalink to &quot;飞行视图工具栏&quot;">​</a></h1><p><img src="'+e+'" alt="飞行视图"></p><h2 id="视图" tabindex="-1">视图 <a class="header-anchor" href="#视图" aria-label="Permalink to &quot;视图&quot;">​</a></h2><p>工具栏左边的“Q”图标允许您在其他顶级视图中选择：</p><ul><li><strong><a href="./../plan_view/plan_view.html">Plan Flight</a>：</strong> 用于创建任务、地理栅栏和集结点</li><li><strong>分析工具：</strong> 用于日志下载、地理标记图像或查看遥测等事项的一组工具。</li><li><strong>车辆配置：</strong> 新车初始配置的各种选项。</li><li><strong>应用程序设置：</strong> QGroundControl应用程序本身的设置。</li></ul><h2 id="工具栏指示器" tabindex="-1">工具栏指示器 <a class="header-anchor" href="#工具栏指示器" aria-label="Permalink to &quot;工具栏指示器&quot;">​</a></h2><p>Next are multiple toolbar indicators for vehicle status. 每个工具栏指示器的下拉功能提供了关于状态的更多细节。 您也可以展开指示器以显示与指示器相关联的其他应用程序和载具设置。 按&quot;&gt;&quot;按钮来扩展。</p><p><img src="'+d+'" alt="工具栏指示器 - 展开按钮"></p><h3 id="flight-status" tabindex="-1">Flight Status <img src="'+a+'" alt="Flight Status indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#flight-status" aria-label="Permalink to &quot;Flight Status &lt;img src=&quot;../../../assets/fly/toolbar/main_status_indicator.png&quot; alt=&quot;Flight Status indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>飞行状态指示器显示载具是否可以飞行。 它可以是下列状态之一：</p><ul><li><strong>准备好飞速</strong> (_绿色背景) - 载具已准备就绪。</li><li><strong>准备好飞行</strong> (_黄色背景) - 载具已准备好在当前飞行模式下飞行。 但有些警告可能造成问题。</li><li><strong>尚未准备好</strong> - 载具没有准备好飞行，也不会起飞。</li><li><strong>解锁</strong> - 载具已解锁并准备起飞。</li><li><strong>飞行</strong> - 载具在空中飞行和飞行中。</li><li><strong>着陆</strong> - 载具正在着陆。</li><li><strong>通信丢失</strong> - QGroundControl已失去与载具的通信。</li></ul><p>The Flight Status indicator dropdown also gives you access to:</p><ul><li><strong>解锁</strong> - 解锁一辆载具开启发动机以准备起飞。 你只有在载具安全和准备飞行时才能解锁载具。 通常你不需要手动解锁载具。 你可以简单地起飞或开始执行任务，载具将解锁自己。</li><li><strong>Disarm</strong> - Disarming a vehicle is only available when the vehicle is on the ground. 它会关停电机。 一般来说，你无需明确进行锁定操作，因为飞行器会在着陆后自动锁定，或者如果在解锁后若未起飞，不久后也会自动锁定。</li><li><strong>紧急停机</strong> - 在载具飞行时用紧急停机锁定载具。 仅供紧急情况使用，你的飞行器会坠毁！</li></ul><p>在警告或尚未准备好状态的情况下，您可以点击指示器来显示下拉菜单，显示原因(s)。 右侧的切换按钮会展开每个错误，并显示更多信息及可能的解决方案。</p><p><img src="'+m+'" alt="用于检查解锁警告的用户界面"></p><p>每个问题解决后，将从用户界面中消失。 当所有阻止解锁的问题被移除时，你现在应该可以准备飞行了。</p><h3 id="flight-mode" tabindex="-1">Flight Mode <img src="'+u+'" alt="Flight Mode indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#flight-mode" aria-label="Permalink to &quot;Flight Mode &lt;img src=&quot;../../../assets/fly/toolbar/flight_modes_indicator.png&quot; alt=&quot;Flight Mode indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>飞行模式指示器显示您当前的飞行模式。 下拉菜单允许您在飞行模式之间切换。 扩展页面允许您：</p><ul><li>配置载具降落设置</li><li>设置全局地理栅栏设置</li><li>从显示列表中添加/删除飞行模式</li></ul><h3 id="vehicle-messages" tabindex="-1">Vehicle Messages <img src="'+p+'" alt="Vehicle Messages indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#vehicle-messages" aria-label="Permalink to &quot;Vehicle Messages &lt;img src=&quot;../../../assets/fly/toolbar/messages_indicator.png&quot; alt=&quot;Vehicle Messages indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>车辆消息指示器下拉显示来自车辆的消息。 如果有重要信息，指示器将会变红。</p><h3 id="gps-rtk-gps" tabindex="-1">GPS / RTK GPS <img src="'+q+'" alt="GPS / RTK GPS indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#gps-rtk-gps" aria-label="Permalink to &quot;GPS / RTK GPS &lt;img src=&quot;../../../assets/fly/toolbar/gps_indicator.png&quot; alt=&quot;GPS / RTK GPS indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The GPS/RTK GPS indicator shows satellite and GNSS status in the toolbar, and the dropdown provides additional GPS details.</p><p>With an active vehicle, the indicator shows vehicle GPS information (for example, satellite count and HDOP), and the expanded page provides access to RTK-related settings.</p><p>When there is no active vehicle but RTK is connected, the indicator switches to RTK status so you can still monitor the correction link.</p><h3 id="gps-resilience" tabindex="-1">GPS Resilience <a class="header-anchor" href="#gps-resilience" aria-label="Permalink to &quot;GPS Resilience&quot;">​</a></h3><p>The GPS Resilience indicator appears when the vehicle reports GPS resilience telemetry (authentication, spoofing, or jamming state). The dropdown provides summary status and per-GPS details when available.</p><h3 id="battery" tabindex="-1">Battery <img src="'+b+'" alt="Battery indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#battery" aria-label="Permalink to &quot;Battery &lt;img src=&quot;../../../assets/fly/toolbar/battery_indicator.png&quot; alt=&quot;Battery indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>电池指示器向您展示了一个可配置的充电图标。 它也可以配置为显示剩余的电压或两种电压。 扩展页面允许您：</p><ul><li>设定电池图标中显示的值 (s)</li><li>配置图标着色</li><li>设置低电量故障安全</li></ul><h3 id="remote-id" tabindex="-1">Remote ID <img src="'+i+'" alt="Remote ID indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#remote-id" aria-label="Permalink to &quot;Remote ID &lt;img src=&quot;../../../assets/fly/toolbar/remote_id_indicator.png&quot; alt=&quot;Remote ID indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The Remote ID indicator appears when Remote ID is available on the active vehicle. Its color indicates overall Remote ID health, and the dropdown shows Remote ID status details.</p><h3 id="esc" tabindex="-1">ESC <img src="'+o+'" alt="ESC indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#esc" aria-label="Permalink to &quot;ESC &lt;img src=&quot;../../../assets/fly/toolbar/esc_indicator.png&quot; alt=&quot;ESC indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The ESC indicator appears when ESC telemetry is available from the vehicle. It shows overall ESC health and online motor count, and opens a detailed ESC status page.</p><h3 id="joystick" tabindex="-1">Joystick <img src="'+l+'" alt="Joystick indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#joystick" aria-label="Permalink to &quot;Joystick &lt;img src=&quot;../../../assets/fly/toolbar/joystick_indicator.png&quot; alt=&quot;Joystick indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The Joystick indicator appears when a joystick/gamepad is detected. The dropdown shows device status and connection details.</p><h3 id="telemetry-rssi" tabindex="-1">Telemetry RSSI <img src="'+r+'" alt="Telemetry RSSI indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#telemetry-rssi" aria-label="Permalink to &quot;Telemetry RSSI &lt;img src=&quot;../../../assets/fly/toolbar/telemetry_rssi_indicator.png&quot; alt=&quot;Telemetry RSSI indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The Telemetry RSSI indicator appears when telemetry signal information is available. It provides local/remote RSSI and additional radio link quality details.</p><h3 id="rc-rssi" tabindex="-1">RC RSSI <img src="'+s+'" alt="RC RSSI indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#rc-rssi" aria-label="Permalink to &quot;RC RSSI &lt;img src=&quot;../../../assets/fly/toolbar/rc_rssi_indicator.png&quot; alt=&quot;RC RSSI indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The RC RSSI indicator appears when RC signal information is available. It shows current RC link strength and opens a page with RC RSSI details.</p><h3 id="gimbal" tabindex="-1">Gimbal <img src="'+n+'" alt="Gimbal indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#gimbal" aria-label="Permalink to &quot;Gimbal &lt;img src=&quot;../../../assets/fly/toolbar/gimbal_indicator.png&quot; alt=&quot;Gimbal indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The Gimbal indicator is shown when the vehicle supports the <a href="https://mavlink.io/en/services/gimbal_v2.html" target="_blank" rel="noreferrer">MAVLink Gimbal Protocol</a>. It displays active gimbal status and provides access to gimbal controls and settings.</p><h3 id="vtol-transitions" tabindex="-1">VTOL Transitions <img src="'+c+'" alt="VTOL indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#vtol-transitions" aria-label="Permalink to &quot;VTOL Transitions &lt;img src=&quot;../../../assets/fly/toolbar/vtol_indicator.png&quot; alt=&quot;VTOL indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>For VTOL vehicles, a VTOL transition status indicator is shown when applicable. It indicates the current VTOL mode/state and provides transition-related status information.</p><h3 id="multi-vehicle-selector" tabindex="-1">Multi-Vehicle Selector <img src="'+h+'" alt="Multi-Vehicle indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#multi-vehicle-selector" aria-label="Permalink to &quot;Multi-Vehicle Selector &lt;img src=&quot;../../../assets/fly/toolbar/multi_vehicle_indicator.png&quot; alt=&quot;Multi-Vehicle indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>The Multi-Vehicle selector appears when more than one vehicle is connected. It allows you to quickly switch the active vehicle from the toolbar.</p><h3 id="apm-support-forwarding" tabindex="-1">APM Support Forwarding <img src="'+g+'" alt="APM Support Forwarding indicator" style="height:1.15em;vertical-align:text-bottom;"> <a class="header-anchor" href="#apm-support-forwarding" aria-label="Permalink to &quot;APM Support Forwarding &lt;img src=&quot;../../../assets/fly/toolbar/apm_support_indicator.png&quot; alt=&quot;APM Support Forwarding indicator&quot; style=&quot;height: 1.15em; vertical-align: text-bottom;&quot; /&gt;&quot;">​</a></h3><p>On ArduPilot, an APM Support Forwarding indicator appears when MAVLink traffic forwarding to a support server is enabled.</p>',48)]))}const M=_(S,[["render",x]]);export{C as __pageData,M as default};
